'use client'

import { createContext, useContext, useMemo, useState, type ReactNode } from 'react'
import type {
  Activity,
  HouseLocation,
  InventoryItem,
  Recipe,
  ServiceExpense,
  ShoppingItem,
  Unit,
  Urgency,
} from '@/lib/types'
import {
  activity as seedActivity,
  household,
  inventory as seedInventory,
  locations as seedLocations,
  members,
  recipes as seedRecipes,
  services as seedServices,
  shopping as seedShopping,
} from '@/lib/mock-data'
import { isLowStock, normalize } from '@/lib/helpers'

let idc = 1000
const uid = (p: string) => `${p}${idc++}`

interface StoreValue {
  currentUser: (typeof members)[number]
  members: typeof members
  household: typeof household
  locations: HouseLocation[]
  inventory: InventoryItem[]
  shopping: ShoppingItem[]
  recipes: Recipe[]
  services: ServiceExpense[]
  activity: Activity[]
  // inventory
  addLocation: (name: string, icon: string) => string
  saveItem: (item: Partial<InventoryItem> & { id?: string }) => void
  deleteItem: (id: string) => void
  // shopping
  addShoppingItem: (data: { name: string; quantity: number; unit: Unit; urgency: Urgency; source?: string }) => void
  toggleBought: (id: string) => void
  setUrgency: (id: string, urgency: Urgency) => void
  deleteShoppingItem: (id: string) => void
  clearBought: () => void
  addToInventoryFromShopping: (data: { name: string; quantity: number; unit: Unit; locationId: string }) => void
  // recipes
  saveRecipe: (recipe: Partial<Recipe> & { id?: string }) => void
  addMissingToShopping: (recipe: Recipe) => number
  // services
  saveService: (svc: Partial<ServiceExpense> & { id?: string }) => void
  toggleServiceStatus: (id: string) => void
  // helpers
  hasInStock: (name: string, needed: number) => boolean
}

const StoreContext = createContext<StoreValue | null>(null)

export function StoreProvider({ children }: { children: ReactNode }) {
  const currentUser = members[0]
  const [locations, setLocations] = useState<HouseLocation[]>(seedLocations)
  const [inventory, setInventory] = useState<InventoryItem[]>(seedInventory)
  const [shopping, setShopping] = useState<ShoppingItem[]>(seedShopping)
  const [recipes, setRecipes] = useState<Recipe[]>(seedRecipes)
  const [services, setServices] = useState<ServiceExpense[]>(seedServices)
  const [activity, setActivity] = useState<Activity[]>(seedActivity)

  function logActivity(text: string, section: Activity['section']) {
    setActivity((prev) => [
      { id: uid('a'), memberId: currentUser.id, text, section, timestamp: 'recién' },
      ...prev,
    ])
  }

  const value = useMemo<StoreValue>(() => {
    function hasInStock(name: string, needed: number) {
      const match = inventory.find((i) => normalize(i.name) === normalize(name))
      return !!match && match.quantity >= needed
    }

    return {
      currentUser,
      members,
      household,
      locations,
      inventory,
      shopping,
      recipes,
      services,
      activity,

      addLocation(name, icon) {
        const id = uid('l')
        setLocations((prev) => [...prev, { id, name, icon }])
        return id
      },

      saveItem(item) {
        if (item.id) {
          setInventory((prev) => prev.map((i) => (i.id === item.id ? { ...i, ...item, updatedBy: currentUser.id, updatedAt: 'recién' } : i)))
          logActivity(`actualizó ${item.name} en el inventario`, 'inventario')
        } else {
          const newItem: InventoryItem = {
            id: uid('i'),
            name: item.name || 'Sin nombre',
            quantity: item.quantity ?? 1,
            unit: (item.unit as Unit) || 'unidades',
            locationId: item.locationId || locations[0].id,
            minStock: item.minStock,
            expiry: item.expiry,
            updatedBy: currentUser.id,
            updatedAt: 'recién',
          }
          setInventory((prev) => [newItem, ...prev])
          logActivity(`agregó ${newItem.name} al inventario`, 'inventario')
        }
      },

      deleteItem(id) {
        setInventory((prev) => prev.filter((i) => i.id !== id))
      },

      addShoppingItem(data) {
        setShopping((prev) => {
          if (prev.some((s) => normalize(s.name) === normalize(data.name) && !s.bought)) return prev
          return [
            {
              id: uid('s'),
              name: data.name,
              quantity: data.quantity,
              unit: data.unit,
              urgency: data.urgency,
              bought: false,
              addedBy: currentUser.id,
              source: data.source || 'manual',
            },
            ...prev,
          ]
        })
        logActivity(`sumó ${data.name} a la lista de compras`, 'compras')
      },

      toggleBought(id) {
        setShopping((prev) => prev.map((s) => (s.id === id ? { ...s, bought: !s.bought } : s)))
      },

      setUrgency(id, urgency) {
        setShopping((prev) => prev.map((s) => (s.id === id ? { ...s, urgency } : s)))
      },

      deleteShoppingItem(id) {
        setShopping((prev) => prev.filter((s) => s.id !== id))
      },

      clearBought() {
        setShopping((prev) => prev.filter((s) => !s.bought))
      },

      addToInventoryFromShopping(data) {
        setInventory((prev) => {
          const existing = prev.find((i) => normalize(i.name) === normalize(data.name) && i.locationId === data.locationId)
          if (existing) {
            return prev.map((i) => (i.id === existing.id ? { ...i, quantity: i.quantity + data.quantity, updatedAt: 'recién', updatedBy: currentUser.id } : i))
          }
          return [
            {
              id: uid('i'),
              name: data.name,
              quantity: data.quantity,
              unit: data.unit,
              locationId: data.locationId,
              updatedBy: currentUser.id,
              updatedAt: 'recién',
            },
            ...prev,
          ]
        })
        logActivity(`sumó ${data.name} al inventario desde compras`, 'inventario')
      },

      saveRecipe(recipe) {
        if (recipe.id) {
          setRecipes((prev) => prev.map((r) => (r.id === recipe.id ? { ...r, ...recipe } as Recipe : r)))
          logActivity(`editó la receta ${recipe.name}`, 'recetero')
        } else {
          const newRecipe: Recipe = {
            id: uid('r'),
            name: recipe.name || 'Nueva receta',
            servings: recipe.servings ?? 2,
            minutes: recipe.minutes ?? 30,
            ingredients: recipe.ingredients || [],
            steps: recipe.steps || [],
          }
          setRecipes((prev) => [newRecipe, ...prev])
          logActivity(`creó la receta ${newRecipe.name}`, 'recetero')
        }
      },

      addMissingToShopping(recipe) {
        const missing = recipe.ingredients.filter((ing) => !hasInStock(ing.name, ing.quantity))
        setShopping((prev) => {
          const next = [...prev]
          for (const ing of missing) {
            if (next.some((s) => normalize(s.name) === normalize(ing.name) && !s.bought)) continue
            next.unshift({
              id: uid('s'),
              name: ing.name,
              quantity: ing.quantity,
              unit: ing.unit,
              urgency: 'medio',
              bought: false,
              addedBy: currentUser.id,
              source: 'receta',
            })
          }
          return next
        })
        if (missing.length) logActivity(`sumó ${missing.length} ingredientes de ${recipe.name} a compras`, 'compras')
        return missing.length
      },

      saveService(svc) {
        if (svc.id) {
          setServices((prev) => prev.map((s) => (s.id === svc.id ? { ...s, ...svc } as ServiceExpense : s)))
          logActivity(`actualizó el gasto de ${svc.category}`, 'servicios')
        } else {
          const newSvc: ServiceExpense = {
            id: uid('e'),
            category: svc.category || 'Otro',
            icon: svc.icon || 'building',
            provider: svc.provider || '',
            amount: svc.amount ?? 0,
            dueDate: svc.dueDate || '2026-07-31',
            status: svc.status || 'pendiente',
            recurrence: svc.recurrence || 'mensual',
          }
          setServices((prev) => [newSvc, ...prev])
          logActivity(`agregó el gasto de ${newSvc.category}`, 'servicios')
        }
      },

      toggleServiceStatus(id) {
        setServices((prev) => prev.map((s) => (s.id === id ? { ...s, status: s.status === 'pagado' ? 'pendiente' : 'pagado' } : s)))
      },

      hasInStock,
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [locations, inventory, shopping, recipes, services, activity])

  return <StoreContext.Provider value={value}>{children}</StoreContext.Provider>
}

export function useStore() {
  const ctx = useContext(StoreContext)
  if (!ctx) throw new Error('useStore debe usarse dentro de StoreProvider')
  return ctx
}

/** Derivados útiles */
export function useLowStock() {
  const { inventory } = useStore()
  return inventory.filter(isLowStock)
}
